export interface Post {
  id: number;
  title: string;
  content: string;
}

const posts: Post[] = [
  { id: 1, title: 'First Post', content: 'This is the first post.' },
  { id: 2, title: 'Second Post', content: 'Another example post.' },
];

export function addPost(title: string, content: string): Post {
  const id = posts.length + 1;
  const post: Post = { id, title, content };
  posts.push(post);
  return post;
}

export function getAllPosts(): Post[] {
  return [...posts];
}

import { cacheTag } from 'next/cache';
import { getAllPosts } from './posts';
import type { Post } from './posts';

export async function getPosts(): Promise<Post[]> {
  'use cache';
  cacheTag('posts');
  return getAllPosts();
}

'use server';

import { updateTag } from 'next/cache';
import { addPost } from './lib/posts';

export async function createPost(formData: FormData) {
  const title = formData.get('title') as string;
  const content = formData.get('content') as string;

  if (!title || !content) {
    throw new Error('Title and content are required');
  }

  addPost(title, content);

  // Immediately expire the 'posts' cache tag.
  // Unlike revalidateTag (which uses stale-while-revalidate and serves stale
  // content while fetching fresh data in the background), updateTag guarantees
  // that the next request blocks and waits for fresh data — no stale content
  // is ever served to the user.
  updateTag('posts');
}

import { getPosts } from './lib/data';
import { createPost } from './actions';

export default async function Home() {
  const posts = await getPosts();

  return (
    <main>
      <h1>Posts</h1>

      <form action={createPost}>
        <label>
          Title: <input name="title" placeholder="Enter a title" required />
        </label>
        <label>
          Content: <input name="content" placeholder="Enter content" required />
        </label>
        <button type="submit">Create Post</button>
      </form>

      <ul>
        {posts.map((post) => (
          <li key={post.id}>
            <h2>{post.title}</h2>
            <p>{post.content}</p>
          </li>
        ))}
      </ul>
    </main>
  );
}

